import okio.buffer

internal class ByteBufferFetcher(
    private val data: ByteBuffer,
    private val options: Options,
) : Fetcher {

    override suspend fun fetch(): FetchResult {
        return SourceFetchResult(
            source = ImageSource(
                source = data.asSource().buffer(),
                fileSystem = options.fileSystem,
                metadata = ByteBufferMetadata(data),
            ),
            mimeType = null,
            dataSource = DataSource.MEMORY,
        )
    }

    class Factory : Fetcher.Factory<ByteBuffer> {

        override fun create(
            data: ByteBuffer,
            options: Options,
            imageLoader: ImageLoader,
        ): Fetcher {
            return ByteBufferFetcher(data, options)
        }
    }
}

internal fun ByteBuffer.asSource() = object : Source {
    private val buffer = this@asSource.slice()
    private val len = buffer.capacity()

    override fun close() = Unit

    override fun read(sink: Buffer, byteCount: Long): Long {
        if (buffer.position() == len) return -1
        val pos = buffer.position()
        val newLimit = (pos + byteCount).toInt().coerceAtMost(len)
        buffer.limit(newLimit)
        return sink.write(buffer).toLong()
    }

    override fun timeout() = Timeout.NONE
}

package coil3.fetch

import coil3.ImageLoader
import coil3.Uri
import coil3.decode.DataSource
import coil3.decode.ImageSource
import coil3.request.Options
import coil3.util.MimeTypeMap
import coil3.util.extension
import okio.Path.Companion.toPath
import okio.openZip

internal class JarFileFetcher(
    private val uri: Uri,
    private val options: Options,
) : Fetcher {

    override suspend fun fetch(): FetchResult {
        val path = uri.path.orEmpty()
        val delimiterIndex = path.indexOf('!')
        check(delimiterIndex != -1) { "Invalid jar:file URI: $uri" }

        val jarPath = path.substring(0, delimiterIndex).toPath()
        val filePath = path.substring(delimiterIndex + 1, path.length).toPath()

        return SourceFetchResult(
            source = ImageSource(filePath, options.fileSystem.openZip(jarPath)),
            mimeType = MimeTypeMap.getMimeTypeFromExtension(filePath.extension),
            dataSource = DataSource.DISK,
        )
    }

    class Factory : Fetcher.Factory<Uri> {
        override fun create(
            data: Uri,
            options: Options,
            imageLoader: ImageLoader,
        ): Fetcher? {
            if (!isApplicable(data)) return null
            return JarFileFetcher(data, options)
        }

        private fun isApplicable(data: Uri): Boolean {
            return data.scheme == "jar:file"
        }
    }
}

package coil3.decode

import coil3.ImageLoader
import coil3.asImage
import coil3.fetch.SourceFetchResult
import coil3.request.Options
import coil3.util.makeFromImage
import okio.use
import org.jetbrains.skia.Bitmap
import org.jetbrains.skia.Image

class SkiaImageDecoder(
    private val source: ImageSource,
    private val options: Options,
) : Decoder {

    override suspend fun decode(): DecodeResult {
        // https://github.com/JetBrains/skiko/issues/741
        val bytes = source.source().use { it.readByteArray() }
        return decodeBitmap(options, bytes)
    }

    class Factory : Decoder.Factory {

        override fun create(
            result: SourceFetchResult,
            options: Options,
            imageLoader: ImageLoader,
        ): Decoder {
            return SkiaImageDecoder(result.source, options)
        }
    }
}

internal expect suspend fun decodeBitmap(options: Options, bytes: ByteArray): DecodeResult

internal fun decodeBitmapSync(options: Options, bytes: ByteArray): DecodeResult {
    val image = Image.makeFromEncoded(bytes)

    val isSampled: Boolean
    val bitmap: Bitmap
    try {
        bitmap = Bitmap.makeFromImage(image, options)
        bitmap.setImmutable()
        isSampled = bitmap.width < image.width || bitmap.height < image.height
    } finally {
        image.close()
    }

    return DecodeResult(
        image = bitmap.asImage(),
        isSampled = isSampled,
    )
}

package coil3.network.internal

import coil3.disk.DiskCache
import coil3.network.NetworkHeaders
import coil3.network.NetworkResponse
import coil3.network.NetworkResponseBody
import okio.Buffer

internal fun NetworkHeaders.Builder.append(line: String) = apply {
    val index = line.indexOf(':')
    require(index != -1) { "Unexpected header: $line" }
    add(line.substring(0, index).trim(), line.substring(index + 1))
}

internal fun DiskCache.Editor.abortQuietly() {
    try {
        abort()
    } catch (_: Exception) {}
}

internal suspend fun NetworkResponseBody.readBuffer(): Buffer = use { body ->
    val buffer = Buffer()
    body.writeTo(buffer)
    return buffer
}

internal expect fun assertNotOnMainThread()

internal const val CACHE_CONTROL = "Cache-Control"
internal const val CONTENT_TYPE = "Content-Type"
internal const val HTTP_METHOD_GET = "GET"
internal const val MIME_TYPE_TEXT_PLAIN = "text/plain"
internal const val HTTP_RESPONSE_OK = 200
internal const val HTTP_RESPONSE_NOT_MODIFIED = 304

internal operator fun NetworkHeaders.plus(other: NetworkHeaders): NetworkHeaders {
    val builder = newBuilder()
    for ((key, values) in other.asMap()) {
        builder[key] = values
    }
    return builder.build()
}

internal fun NetworkResponse.requireBody(): NetworkResponseBody {
    return checkNotNull(body) { "body == null" }
}

internal fun AutoCloseable.closeQuietly() {
    try {
        close()
    } catch (e: RuntimeException) {
        throw e
    } catch (_: Exception) {}
}

